head.b:skin:
:root{--black:#000;--white:#fff;--bg:#fff;--grey:#6b6b6b;--grey-light:#f4f4f4;--gold:#d4af37;--gold-dark:#b8951f;--red:#e63946;--blue:#1a1a2e;--dark:#0a0a0a}
*,*::before,*::after{margin:0;padding:0;box-sizing:border-box}
html{scroll-behavior:smooth;overflow-x:hidden}
body{font-family:'Inter',sans-serif;font-size:16px;line-height:1.55;color:#000;background:#fff;overflow-x:hidden;-webkit-font-smoothing:antialiased}
img{max-width:100%;height:auto;display:block}
a{color:inherit;text-decoration:none;transition:color .25s}
ul,ol{list-style:none}
button,input,textarea{font-family:inherit;border:none;outline:none;background:none}
h1,h2,h3,h4,h5,h6{font-family:'Oswald',sans-serif;font-weight:600;line-height:1.1;text-transform:uppercase}
.bpa-wrap{max-width:1440px;margin:0 auto;padding:0 32px}
.bpa-grid{display:grid;grid-template-columns:repeat(12,1fr);gap:30px}
.bpa-c2{grid-column:span 2}.bpa-c3{grid-column:span 3}.bpa-c4{grid-column:span 4}.bpa-c5{grid-column:span 5}.bpa-c6{grid-column:span 6}.bpa-c7{grid-column:span 7}.bpa-c8{grid-column:span 8}.bpa-c9{grid-column:span 9}.bpa-c12{grid-column:1/-1}
.bpa-btn{display:inline-block;padding:14px 30px;font-family:'Oswald',sans-serif;font-size:14px;font-weight:600;letter-spacing:1.5px;text-transform:uppercase;cursor:pointer;transition:all .3s ease;border:2px solid transparent}
.bpa-btn-gold{background:#d4af37;color:#000}.bpa-btn-gold:hover{background:#b8951f}
.bpa-btn-red{background:#e63946;color:#fff}.bpa-btn-red:hover{background:#c82a37}
.bpa-btn-out{background:transparent;border:2px solid #fff;color:#fff}.bpa-btn-out:hover{background:#fff;color:#000}
.bpa-tag{display:inline-block;padding:4px 10px;background:#d4af37;color:#000;font-size:11px;font-family:'Oswald',sans-serif;font-weight:600;text-transform:uppercase;letter-spacing:1px;margin-right:6px;margin-bottom:6px}
.bpa-h{position:fixed;top:0;left:0;width:100%;z-index:90;padding:18px 32px;background:transparent;transition:all .3s ease}
.bpa-h.scrolled{background:rgba(10,10,10,.95);padding:12px 32px}
.bpa-logo{display:flex;align-items:center;gap:14px}
.bpa-logo img{height:54px;width:54px;border-radius:50%;border:2px solid #d4af37;object-fit:cover}
.bpa-lt{font-family:'Oswald',sans-serif;font-size:18px;font-weight:700;color:#fff;text-transform:uppercase;line-height:1.1}
.bpa-lt small{display:block;font-size:9px;font-weight:400;letter-spacing:2px;color:#d4af37;margin-top:3px}
.bpa-h-soc a{color:#fff;font-size:18px;margin:0 8px}
.bpa-h-soc a:hover{color:#d4af37}
.bpa-mt{position:relative;width:80px;height:40px;cursor:pointer;display:inline-block;vertical-align:middle}
.bpa-mt span{position:absolute;left:0;width:28px;height:2px;background:#fff;transition:all .3s ease}
.bpa-mt span:nth-child(1){top:14px}.bpa-mt span:nth-child(2){top:22px}
.bpa-mt.active span:nth-child(1){top:18px;transform:rotate(45deg)}
.bpa-mt.active span:nth-child(2){top:18px;transform:rotate(-45deg)}
.bpa-mt em{font-family:'Oswald',sans-serif;font-style:normal;font-size:13px;color:#fff;letter-spacing:1px;position:absolute;left:36px;top:12px;text-transform:uppercase;font-weight:500}
.bpa-nav{position:fixed;top:0;left:0;width:100%;height:100%;z-index:100;opacity:0;visibility:hidden;transition:all .4s}
.bpa-nav.active{opacity:1;visibility:visible}
.bpa-nav-bg{position:fixed;top:0;right:0;width:60%;height:100%;background-size:cover;background-position:center;z-index:1}
.bpa-nav-h{position:fixed;top:0;left:0;width:50%;min-width:600px;height:100%;background:#1a1a2e;z-index:20;padding:140px 50px 50px;overflow-y:auto}
.bpa-nav-top{position:fixed;top:0;left:0;width:100%;padding:18px 32px;z-index:30;display:flex;justify-content:space-between;align-items:center}
.bpa-nav-h ul li{margin-bottom:6px}
.bpa-nav-h ul li a{display:inline-block;font-family:'Oswald',sans-serif;font-size:38px;font-weight:600;color:#fff;text-transform:uppercase;line-height:1.2;transition:all .25s}
.bpa-nav-h ul li a:hover{color:#d4af37;padding-left:10px}
.bpa-hero{position:relative;overflow:hidden}
.bpa-slide{position:relative;height:770px;width:100%;background-size:cover;background-position:center;display:none}
.bpa-slide.active{display:block}
.bpa-slide::before{content:'';position:absolute;inset:0;background:linear-gradient(to right,rgba(0,0,0,.6),rgba(0,0,0,.15));z-index:1}
.bpa-slide-i{position:absolute;top:50%;left:0;transform:translateY(-50%);padding:0 96px;z-index:5;width:100%}
.bpa-slide h1{font-size:56px;color:#fff;font-family:'Oswald',sans-serif;font-weight:600;max-width:860px;margin-bottom:40px;line-height:1.05;text-transform:uppercase}
.bpa-dots{position:absolute;bottom:40px;left:96px;display:flex;gap:12px;z-index:10}
.bpa-dots .d{width:50px;height:3px;background:rgba(255,255,255,.4);cursor:pointer;transition:all .3s}
.bpa-dots .d.active{background:#d4af37;height:5px}
.bpa-st{font-size:42px;text-transform:uppercase;line-height:1.1}
.bpa-ss{font-size:17px;line-height:1.6;color:#333;max-width:780px;margin-top:24px}
.bpa-disc{margin-top:60px;padding-bottom:60px;position:relative}
.bpa-card{position:relative;height:560px;display:block;overflow:hidden}
.bpa-card.r{background:#e63946}.bpa-card.b{background:#1a1a2e}.bpa-card.k{background:#000}
.bpa-card-i{position:absolute;background-size:cover;background-position:center;transition:transform .5s}
.bpa-card-i.tl{top:40px;left:40px;right:40px;bottom:40px}
.bpa-card-i.tr{top:0;left:0;right:64px;bottom:97px}
.bpa-card-i.br{bottom:0;right:0;left:64px;top:96px}
.bpa-card:hover .bpa-card-i{transform:scale(1.04)}
.bpa-card-t{position:absolute;z-index:10}
.bpa-card-t.tl{top:14px;left:22px}
.bpa-card-t.bl{bottom:48px;left:22px}
.bpa-card-t.bm{bottom:33%;left:22px}
.bpa-card h3{color:#fff;font-size:26px;line-height:1.1;margin-bottom:20px}
.bpa-card .arr{display:inline-block;color:#fff;font-size:24px}
.bpa-marq{background:#d4af37;padding:18px 0;overflow:hidden;white-space:nowrap;margin:60px 0 0}
.bpa-marq-c{display:inline-block;animation:bpamarq 30s linear infinite}
.bpa-marq-c span{font-family:'Oswald',sans-serif;font-size:18px;font-weight:600;color:#000;text-transform:uppercase;padding:0 4px;letter-spacing:1px}
@keyframes bpamarq{0%{transform:translateX(0)}100%{transform:translateX(-50%)}}
.bpa-mc{display:block;margin-bottom:48px}
.bpa-mc .img{position:relative;background-size:cover;background-position:center;margin-bottom:18px}
.bpa-mc .img::after{content:'';display:block;padding-bottom:100%}
.bpa-mc h4{font-size:21px;line-height:1.3;font-family:'Oswald',sans-serif;font-weight:600;text-transform:none}
.bpa-mc:hover h4{color:#d4af37}
.bpa-vb{align-items:center;border-bottom:1px solid rgba(0,0,0,.15);padding-bottom:60px;margin:80px 0}
.bpa-vb h2{font-size:42px;margin-bottom:20px;text-transform:uppercase}
.bpa-vb p{font-size:17px;line-height:1.7;color:#333;white-space:pre-line}
.bpa-vid{position:relative;padding-bottom:56.25%;height:0;overflow:hidden}
.bpa-vid iframe{position:absolute;inset:0;width:100%;height:100%;border:0}
.bpa-mem{margin:80px 0;display:grid;grid-template-columns:1fr 1fr;gap:30px}
.bpa-mem-c{position:relative;overflow:hidden}
.bpa-mem-c::after{content:'';display:block;padding-bottom:100%}
.bpa-mem-c.tall::after{padding-bottom:120%}
.bpa-mem-c .bg{position:absolute;inset:0;background-size:cover;background-position:center}
.bpa-mem-c .bg::before{content:'';position:absolute;inset:0;background:linear-gradient(to top,rgba(0,0,0,.75),rgba(0,0,0,.3))}
.bpa-mem-c .tw{position:absolute;z-index:10}
.bpa-mem-c.l .tw{bottom:26%;left:5%}
.bpa-mem-c.r .tw{top:26%;right:5%;text-align:right}
.bpa-mem-c h3{font-size:38px;color:#fff;line-height:1;margin-bottom:24px}
.bpa-coach{position:relative;height:580px;background:#000;overflow:hidden}
.bpa-coach .img{position:absolute;left:0;top:64px;right:270px;bottom:0;background-size:cover;background-position:center}
.bpa-coach .tx{position:absolute;top:50%;right:56px;transform:translateY(-50%);z-index:10}
.bpa-coach h3{font-size:38px;color:#fff;line-height:1;margin-bottom:28px}
.bpa-evbg{background:#f4f4f4;margin-top:60px;padding:60px 0}
.bpa-ev{display:block;margin-bottom:48px}
.bpa-ev .img{position:relative;background-size:cover;background-position:center;margin-bottom:18px;background:#e63946}
.bpa-ev .img::after{content:'';display:block;padding-bottom:70%}
.bpa-ev .img .dt{position:absolute;top:8px;left:14px;color:#fff;font-size:30px;font-weight:600;font-family:'Oswald',sans-serif}
.bpa-ev h4{font-size:17px;font-family:'Oswald',sans-serif;text-transform:uppercase;letter-spacing:.5px;line-height:1.3;font-weight:600}
.bpa-ev p{font-size:15px;color:#333;margin-top:8px;line-height:1.55}
.bpa-news{margin-top:80px;padding-bottom:60px}
.bpa-nc{display:block;margin-bottom:48px}
.bpa-nc .img{position:relative;background-size:cover;background-position:center;margin-bottom:18px;background:#1a1a2e}
.bpa-nc .img::after{content:'';display:block;padding-bottom:70%}
.bpa-nc h4{font-size:17px;font-family:'Oswald',sans-serif;text-transform:uppercase;letter-spacing:.5px;line-height:1.3;font-weight:600;margin-top:8px}
.bpa-nc p{font-size:15px;color:#333;margin-top:8px;line-height:1.55}
.bpa-nl{background-size:cover;background-position:center;color:#fff;position:relative}
.bpa-nl::before{content:'';position:absolute;inset:0;background:rgba(0,0,0,.7)}
.bpa-nl .bpa-wrap{position:relative;z-index:2}
.bpa-nl h2{font-size:42px;color:#fff;text-transform:uppercase}
.bpa-nl p{font-size:17px;line-height:1.6;margin-top:24px;max-width:630px}
.bpa-nl input[type='email']{width:100%;padding:14px 20px;background:#fff;color:#000}
.bpa-nl .pn{font-size:14px;margin-top:80px;max-width:630px;line-height:1.6;opacity:.85}
.bpa-f{background:#000;color:#fff;padding:64px 0 16px}
.bpa-f .fl-img{height:32px;width:auto;display:inline-block;margin-left:24px;margin-bottom:8px;filter:brightness(0) invert(1) opacity(.85)}
.bpa-f-cols{margin-top:80px;display:grid;grid-template-columns:repeat(5,1fr);gap:30px}
.bpa-f-cols h3{color:#d4af37;font-family:'Oswald',sans-serif;font-size:13px;text-transform:uppercase;letter-spacing:1px;font-weight:600;margin-bottom:12px}
.bpa-f-cols ul{margin-top:8px;line-height:1.9}
.bpa-f-cols ul li a{font-size:14px;color:#fff;transition:all .25s}
.bpa-f-cols ul li a:hover{color:#d4af37;padding-left:5px}
.bpa-f-bot{margin-top:60px;padding-top:24px;border-top:1px solid rgba(255,255,255,.2);display:grid;grid-template-columns:1fr 1fr;align-items:center;gap:20px}
.bpa-f-bot .soc a{display:inline-block;margin-right:16px;color:#fff;font-size:20px}
.bpa-f-bot .soc a:hover{color:#d4af37}
.bpa-f-bot .lg{text-align:right;font-size:14px}
.bpa-f-bot .lg a{margin-left:24px}
.bpa-f-bot .lg a:hover{color:#d4af37}
.bpa-post{padding:140px 0 80px;max-width:900px;margin:0 auto}
.bpa-post h1{font-size:48px;margin-bottom:20px;text-transform:uppercase;line-height:1.1}
.bpa-post .meta{font-size:14px;color:#6b6b6b;margin-bottom:28px}
.bpa-post .body{font-size:17px;line-height:1.8;color:#222}
.bpa-post .body p{margin-bottom:18px}
.bpa-post .body img{margin:24px 0;width:100%;height:auto}
.bpa-post .body a{color:#d4af37;text-decoration:underline}
.bpa-post .body h2,.bpa-post .body h3{margin:32px 0 16px;font-family:'Oswald',sans-serif;text-transform:uppercase}
.bpa-post .body blockquote{border-left:4px solid #d4af37;padding:8px 24px;margin:24px 0;font-style:italic;color:#444}
.bpa-pag{display:flex;justify-content:center;gap:12px;padding:40px 0}
.bpa-pag a{padding:12px 24px;background:#f4f4f4;font-family:'Oswald',sans-serif;font-size:14px;text-transform:uppercase;letter-spacing:1px;font-weight:600}
.bpa-pag a:hover{background:#d4af37;color:#000}
.bpa-circ{position:absolute;width:227px;height:227px;left:25%;top:24%;z-index:1;transform:rotate(-12deg);opacity:.15;background:#d4af37;border-radius:50%}
.bpa-circ2{position:absolute;width:330px;height:330px;left:52%;top:45%;z-index:1;background:#d4af37;border-radius:50%;opacity:.08}
.bpa-hide-m{display:inline-block}
@media(max-width:1024px){
.bpa-wrap{padding:0 24px}.bpa-h{padding:14px 24px}
.bpa-slide{height:600px}.bpa-slide-i{padding:0 40px}.bpa-slide h1{font-size:38px;max-width:700px}
.bpa-st,.bpa-vb h2,.bpa-nl h2{font-size:32px}
.bpa-c3,.bpa-c4,.bpa-c5,.bpa-c6,.bpa-c7,.bpa-c8,.bpa-c9{grid-column:span 6}
.bpa-card,.bpa-coach{height:460px}
.bpa-coach .img{right:30px}
.bpa-f-cols{grid-template-columns:repeat(3,1fr)}
.bpa-nav-h{width:60%}
}
@media(max-width:768px){
.bpa-wrap{padding:0 16px}.bpa-h{padding:12px 16px}
.bpa-btn{padding:12px 22px;font-size:13px}
.bpa-slide{height:500px}.bpa-slide-i{padding:0 24px}.bpa-slide h1{font-size:26px;max-width:340px;margin-bottom:28px}
.bpa-dots{left:24px;bottom:24px}.bpa-dots .d{width:30px}
.bpa-st,.bpa-vb h2,.bpa-nl h2{font-size:26px}
.bpa-c2,.bpa-c3,.bpa-c4,.bpa-c5,.bpa-c6,.bpa-c7,.bpa-c8,.bpa-c9{grid-column:1/-1}
.bpa-disc{margin-top:48px}.bpa-card{height:320px}
.bpa-marq{margin:30px 0}.bpa-marq-c span{font-size:14px}
.bpa-vb{margin:24px 0 40px;padding-bottom:30px}
.bpa-mem{grid-template-columns:1fr;gap:14px;margin:30px 0 48px}
.bpa-mem-c::after{padding-bottom:130%}
.bpa-mem-c .tw{bottom:24px!important;top:auto!important;left:24px!important;right:24px!important;text-align:left!important}
.bpa-mem-c h3{font-size:24px}
.bpa-coach{height:380px}.bpa-coach .img{right:30px;top:40px;bottom:auto;height:60%}
.bpa-coach .tx{right:24px;top:auto;bottom:32px;transform:none;left:24px}
.bpa-coach h3{font-size:28px}
.bpa-evbg{margin-top:24px;padding:48px 0}.bpa-news{margin-top:48px}
.bpa-f{padding:32px 0 16px}
.bpa-f-cols{margin-top:32px;grid-template-columns:repeat(2,1fr);gap:14px}
.bpa-f-bot{grid-template-columns:1fr;text-align:left}
.bpa-f-bot .lg{text-align:left}
.bpa-f-bot .lg a{margin-left:0;margin-right:18px;display:inline-block}
.bpa-nav-h{width:100%;min-width:0;padding:90px 24px 24px}
.bpa-nav-h ul li a{font-size:26px}
.bpa-post{padding:100px 0 48px}.bpa-post h1{font-size:30px}
}
@media(max-width:480px){
.bpa-logo img{height:42px;width:42px}
.bpa-lt{font-size:14px}
.bpa-mt{width:60px}.bpa-mt em{font-size:11px;left:32px}
.bpa-btn{font-size:12px;padding:10px 18px}
.bpa-slide{height:440px}.bpa-slide h1{font-size:22px}
.bpa-f-cols{grid-template-columns:1fr}
.bpa-hide-m{display:none}
}
@media(max-width:768px){.bpa-hide-m{display:none}}

body.script:
//
function bpaToggleNav(){var n=document.getElementById('bpaNav'),m=document.getElementById('bpaMt');n.classList.toggle('active');m.classList.toggle('active');document.body.style.overflow=n.classList.contains('active')?'hidden':'';}
window.addEventListener('scroll',function(){var h=document.getElementById('bpaHead');if(!h)return;if(window.scrollY>50)h.classList.add('scrolled');else h.classList.remove('scrolled');});
var bpaCur=0;var bpaSlides=document.querySelectorAll('.bpa-slide');var bpaDots=document.querySelectorAll('.bpa-dots .d');
function bpaSlide(n){if(!bpaSlides.length)return;bpaSlides[bpaCur].classList.remove('active');if(bpaDots[bpaCur])bpaDots[bpaCur].classList.remove('active');bpaCur=n;bpaSlides[bpaCur].classList.add('active');if(bpaDots[bpaCur])bpaDots[bpaCur].classList.add('active');}
function bpaNext(){if(bpaSlides.length)bpaSlide((bpaCur+1)%bpaSlides.length);}
if(bpaSlides.length>1)setInterval(bpaNext,5500);
function bpaSubscribe(e){e.preventDefault();var em=document.getElementById('bpaEmail').value;var r=document.getElementById('bpaResp');if(em){r.textContent='Thank you for subscribing to BPA newsletter!';document.getElementById('bpaSignup').reset();}return false;}
//
